// src/pages/Presence.jsx
import React, { useState, useEffect } from 'react';
import { getSeances, getMembresSimple, getPresencePourSeance, marquerPresence } from '../services/api';

function Presence() {
  const [seances, setSeances] = useState([]);
  const [selectedSeance, setSelectedSeance] = useState('');
  const [membres, setMembres] = useState([]);
  const [presences, setPresences] = useState({}); // { id_membre: 'Présent' | 'Absent' | 'Inscrit' }

  // Charger toutes les séances au démarrage
  useEffect(() => {
    const chargerSeances = async () => {
      try {
        const res = await getSeances();
        setSeances(res.data || []);
      } catch (err) {
        console.error('Erreur chargement des séances:', err);
      }
    };
    chargerSeances();
  }, []);

  // Quand on sélectionne une séance
  const handleChangeSeance = async (e) => {
    const id = e.target.value;
    setSelectedSeance(id);

    if (id) {
      try {
        // Charger les membres
        const membresRes = await getMembresSimple();
        setMembres(membresRes.data || []);

        // Charger l'état de présence actuel pour cette séance
        const presenceRes = await getPresencePourSeance(id);
        const mapPresence = {};
        presenceRes.data.forEach(p => {
          mapPresence[p.id_membre] = p.statut;
        });
        setPresences(mapPresence);
      } catch (err) {
        console.error('Erreur chargement présence:', err);
      }
    } else {
      setMembres([]);
      setPresences({});
    }
  };

  // Marquer la présence (Présent / Absent)
  const handleMarquer = async (id_membre, statut) => {
    try {
      await marquerPresence({
        id_seance: selectedSeance,
        id_membre,
        statut,
      });

      // Mettre à jour l'affichage immédiatement
      setPresences(prev => ({
        ...prev,
        [id_membre]: statut,
      }));

      alert(`Statut mis à jour : ${statut}`);
    } catch (err) {
      alert('Erreur lors de l’enregistrement');
      console.error(err);
    }
  };

  return (
    <div className="container mt-5">
      <h2 className="mb-4 text-center">Suivi de Présence</h2>

      {/* Sélection de la séance */}
      <div className="card shadow mb-5">
        <div className="card-body">
          <label className="form-label fw-bold">Choisir une séance</label>
          <select
            className="form-select"
            value={selectedSeance}
            onChange={handleChangeSeance}
          >
            <option value="">-- Sélectionner une séance --</option>
            {seances.map((s) => (
              <option key={s.id_seance} value={s.id_seance}>
                {s.date} à {s.heure} - {s.nom_sport || 'Sport inconnu'} - Coach : {s.nom_coach || 'Inconnu'}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Affichage seulement si une séance est sélectionnée */}
      {selectedSeance && (
        <>
          <h4 className="mb-3">Liste des membres</h4>

          {membres.length === 0 ? (
            <div className="alert alert-info">
              Aucun membre disponible
            </div>
          ) : (
            <div className="table-responsive">
              <table className="table table-striped table-hover table-bordered">
                <thead className="table-dark">
                  <tr>
                    <th>Nom</th>
                    <th>Prénom</th>
                    <th>Statut actuel</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {membres.map((m) => (
                    <tr key={m.id_personne}>
                      <td>{m.nom}</td>
                      <td>{m.prenom}</td>
                      <td className={
                        presences[m.id_personne] === 'Présent' ? 'text-success fw-bold' :
                        presences[m.id_personne] === 'Absent' ? 'text-danger fw-bold' :
                        'text-secondary'
                      }>
                        {presences[m.id_personne] || 'Non inscrit'}
                      </td>
                      <td>
                        <button
                          className="btn btn-success btn-sm me-2"
                          onClick={() => handleMarquer(m.id_personne, 'Présent')}
                        >
                          Présent
                        </button>
                        <button
                          className="btn btn-danger btn-sm"
                          onClick={() => handleMarquer(m.id_personne, 'Absent')}
                        >
                          Absent
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}
    </div>
  );
}

export default Presence;
